import { useState, useRef, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { useLandmarkEdit, LandmarkEditField } from "@/hooks/useLandmarkEdit";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { Bot, Send, Loader2, Check, X, Minimize2 } from "lucide-react";
import ReactMarkdown from "react-markdown";

interface AIEdit {
  fieldName: string;
  newValue: string;
}

interface Message {
  role: "user" | "assistant";
  content: string;
  edits?: AIEdit[];
}

interface LandmarkAIEditPanelProps {
  open: boolean;
  onClose: () => void;
  restaurant: any;
  onEditSuccess: () => void;
}

const LandmarkAIEditPanel = ({
  open,
  onClose,
  restaurant,
  onEditSuccess,
}: LandmarkAIEditPanelProps) => {
  const { t, i18n } = useTranslation();
  const { submitEdits, isSubmitting } = useLandmarkEdit(restaurant?.id || "");
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [pendingEdits, setPendingEdits] = useState<AIEdit[] | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, pendingEdits]);

  // Reset on close
  useEffect(() => {
    if (!open) {
      setMessages([]);
      setInput("");
      setPendingEdits(null);
    }
  }, [open]);

  const buildLandmarkContext = () => {
    const info = restaurant?.landmark_info || {};
    return {
      name: restaurant?.name || "",
      name_en: restaurant?.name_en || "",
      name_pt: restaurant?.name_pt || "",
      description: restaurant?.description_zh || restaurant?.description_en || "",
      address: restaurant?.address || "",
      phone: restaurant?.phone || "",
      email: restaurant?.email || "",
      website: info.website || "",
      subtitle: info.subtitle || "",
      ticket: info.ticket || "",
      transport: info.transport || "",
      tips: info.tips || "",
      openingHours: info.openingHours || "",
      bestSeason: info.bestSeason || "",
      duration: info.duration || "",
      geology: info.geology || "",
      altitude: info.altitude || "",
    };
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = { role: "user", content: input.trim() };
    setMessages(prev => [...prev, userMsg]);
    setInput("");
    setIsLoading(true);

    try {
      const { data, error } = await supabase.functions.invoke("ai-landmark-edit", {
        body: {
          landmark: buildLandmarkContext(),
          message: userMsg.content,
          history: messages.map(m => ({ role: m.role, content: m.content })),
          lang: i18n.language,
        },
      });

      if (error) throw error;

      const reply = data?.reply || t("landmark.edit.aiEditDesc");
      const edits: AIEdit[] = data?.edits || [];

      const assistantMsg: Message = { role: "assistant", content: reply, edits };
      setMessages(prev => [...prev, assistantMsg]);

      if (edits.length > 0) {
        setPendingEdits(edits);
      }
    } catch (err) {
      console.error("AI edit error:", err);
      toast.error(t("landmark.edit.submitFailed"));
      setMessages(prev => [
        ...prev,
        { role: "assistant", content: t("landmark.edit.submitFailed") },
      ]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleConfirmEdits = async () => {
    if (!pendingEdits || pendingEdits.length === 0) return;

    const currentInfo = buildLandmarkContext();
    const editFields: LandmarkEditField[] = pendingEdits.map(e => ({
      fieldName: e.fieldName,
      oldValue: (currentInfo as any)[e.fieldName] || "",
      newValue: e.newValue,
    }));

    const success = await submitEdits(editFields, i18n.language);
    if (success) {
      toast.success(t("landmark.edit.aiApplied"));
      setPendingEdits(null);
      onEditSuccess();
      // Don't close — user can continue editing
    }
  };

  const handleRejectEdits = () => {
    setPendingEdits(null);
  };

  const fieldLabelMap: Record<string, string> = {
    name: t("landmark.edit.fieldName"),
    description: t("landmark.edit.fieldDescription"),
    subtitle: t("landmark.edit.fieldSubtitle"),
    address: t("landmark.edit.fieldAddress"),
    phone: t("landmark.edit.fieldPhone"),
    email: t("landmark.edit.fieldEmail"),
    website: t("landmark.edit.fieldWebsite"),
    ticket: t("landmark.ticket", "门票"),
    transport: t("landmark.edit.fieldTransport"),
    tips: t("landmark.edit.fieldTips"),
    openingHours: t("landmark.openingHours", "开放时间"),
    bestSeason: t("landmark.bestSeason", "最佳季节"),
    duration: t("landmark.duration", "建议游览时间"),
    geology: t("landmark.geology", "地貌"),
    altitude: t("landmark.altitude", "海拔"),
    yearBuilt: t("landmark.yearBuilt", "建成年份"),
  };

  if (!open) return null;

  return (
    <>
      {/* Mobile: full-screen overlay */}
      <div className="fixed inset-0 z-50 flex flex-col bg-background md:hidden">
        {/* Header */}
        <div className="px-4 py-3 shrink-0 border-b flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Bot className="w-5 h-5 text-primary" />
            <span className="text-sm font-semibold">{t("landmark.edit.aiEdit")}</span>
          </div>
          <Button variant="ghost" size="icon" className="h-8 w-8" onClick={onClose}>
            <X className="w-4 h-4" />
          </Button>
        </div>

        {/* Chat messages */}
        <div ref={scrollRef} className="flex-1 min-h-0 overflow-y-auto p-4 space-y-3">
          {messages.length === 0 && (
            <div className="flex justify-start">
              <div className="max-w-[90%] rounded-2xl px-4 py-3 text-sm bg-muted">
                <div className="prose prose-sm dark:prose-invert max-w-none whitespace-pre-line">
                  {t("landmark.edit.aiGreeting")}
                </div>
              </div>
            </div>
          )}
          {messages.map((msg, i) => (
            <div
              key={i}
              className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}
            >
              <div
                className={`max-w-[80%] rounded-2xl px-4 py-2.5 text-sm ${
                  msg.role === "user"
                    ? "bg-primary text-primary-foreground"
                    : "bg-muted"
                }`}
              >
                <div className={`prose prose-sm max-w-none ${
                  msg.role === "user"
                    ? "[&_*]:text-primary-foreground [&_p]:text-primary-foreground"
                    : "dark:prose-invert"
                }`}>
                  <ReactMarkdown>{msg.content}</ReactMarkdown>
                </div>
              </div>
            </div>
          ))}
          {isLoading && (
            <div className="flex justify-start">
              <div className="bg-muted rounded-2xl px-4 py-2.5">
                <Loader2 className="w-4 h-4 animate-spin text-muted-foreground" />
              </div>
            </div>
          )}
        </div>

        {/* Pending edits confirmation */}
        {pendingEdits && pendingEdits.length > 0 && (
          <div className="border-t bg-accent/30 p-4 space-y-3 shrink-0">
            <div className="text-sm font-medium">{t("landmark.edit.aiConfirm")}</div>
            <div className="space-y-2 max-h-[40vh] overflow-y-auto">
              {pendingEdits.map((edit, i) => (
                <div key={i} className="text-sm bg-background rounded-lg px-3 py-2 space-y-0.5">
                  <div className="font-medium text-primary text-xs">
                    {fieldLabelMap[edit.fieldName] || edit.fieldName}
                  </div>
                  <div className="text-foreground text-xs break-words">{edit.newValue}</div>
                </div>
              ))}
            </div>
            <div className="flex gap-3">
              <Button size="sm" className="h-9 text-sm flex-1" onClick={handleConfirmEdits} disabled={isSubmitting}>
                {isSubmitting ? <Loader2 className="w-3.5 h-3.5 animate-spin mr-1.5" /> : <Check className="w-3.5 h-3.5 mr-1.5" />}
                {t("common.confirm", "确认")}
              </Button>
              <Button size="sm" variant="outline" className="h-9 text-sm flex-1" onClick={handleRejectEdits}>
                <X className="w-3.5 h-3.5 mr-1.5" />
                {t("common.cancel", "取消")}
              </Button>
            </div>
          </div>
        )}

        {/* Input area */}
        <div className="border-t p-3 pb-safe flex gap-2 shrink-0">
          <Textarea
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => {
              if (e.key === "Enter" && !e.shiftKey) {
                e.preventDefault();
                handleSend();
              }
            }}
            placeholder={t("landmark.edit.aiPlaceholder")}
            className="min-h-[40px] max-h-[80px] resize-none text-sm rounded-xl"
            rows={1}
          />
          <Button
            size="icon"
            className="shrink-0 h-10 w-10 rounded-xl"
            onClick={handleSend}
            disabled={!input.trim() || isLoading}
          >
            <Send className="w-4 h-4" />
          </Button>
        </div>
      </div>

      {/* Desktop: floating panel */}
      <div className="hidden md:flex fixed bottom-4 right-4 z-50 w-[380px] h-[520px] flex-col bg-background border rounded-xl shadow-2xl overflow-hidden">
        {/* Header */}
        <div className="px-4 py-3 shrink-0 border-b flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Bot className="w-5 h-5 text-primary" />
            <span className="text-sm font-semibold">{t("landmark.edit.aiEdit")}</span>
          </div>
          <Button variant="ghost" size="icon" className="h-7 w-7" onClick={onClose}>
            <Minimize2 className="w-4 h-4" />
          </Button>
        </div>

        {/* Chat messages */}
        <div ref={scrollRef} className="flex-1 min-h-0 overflow-y-auto p-3 space-y-3">
          {messages.length === 0 && (
            <div className="flex justify-start">
              <div className="max-w-[90%] rounded-lg px-3 py-2 text-sm bg-muted">
                <div className="prose prose-sm dark:prose-invert max-w-none whitespace-pre-line">
                  {t("landmark.edit.aiGreeting")}
                </div>
              </div>
            </div>
          )}
          {messages.map((msg, i) => (
            <div
              key={i}
              className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}
            >
              <div
                className={`max-w-[85%] rounded-lg px-3 py-2 text-sm ${
                  msg.role === "user"
                    ? "bg-primary text-primary-foreground"
                    : "bg-muted"
                }`}
              >
                <div className={`prose prose-sm max-w-none ${
                  msg.role === "user"
                    ? "[&_*]:text-primary-foreground [&_p]:text-primary-foreground"
                    : "dark:prose-invert"
                }`}>
                  <ReactMarkdown>{msg.content}</ReactMarkdown>
                </div>
              </div>
            </div>
          ))}
          {isLoading && (
            <div className="flex justify-start">
              <div className="bg-muted rounded-lg px-3 py-2">
                <Loader2 className="w-4 h-4 animate-spin text-muted-foreground" />
              </div>
            </div>
          )}
        </div>

        {/* Pending edits confirmation */}
        {pendingEdits && pendingEdits.length > 0 && (
          <div className="border-t bg-accent/50 p-3 space-y-2">
            <div className="text-xs font-medium">{t("landmark.edit.aiConfirm")}</div>
            <div className="space-y-1 max-h-24 overflow-y-auto">
              {pendingEdits.map((edit, i) => (
                <div key={i} className="text-xs bg-background rounded px-2 py-1 flex gap-2">
                  <span className="font-medium text-primary shrink-0">
                    {fieldLabelMap[edit.fieldName] || edit.fieldName}:
                  </span>
                  <span className="text-foreground truncate">{edit.newValue}</span>
                </div>
              ))}
            </div>
            <div className="flex gap-2">
              <Button size="sm" className="h-7 text-xs" onClick={handleConfirmEdits} disabled={isSubmitting}>
                {isSubmitting ? <Loader2 className="w-3 h-3 animate-spin mr-1" /> : <Check className="w-3 h-3 mr-1" />}
                {t("common.confirm", "确认")}
              </Button>
              <Button size="sm" variant="outline" className="h-7 text-xs" onClick={handleRejectEdits}>
                <X className="w-3 h-3 mr-1" />
                {t("common.cancel", "取消")}
              </Button>
            </div>
          </div>
        )}

        {/* Input area */}
        <div className="border-t p-2 flex gap-2 shrink-0">
          <Textarea
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => {
              if (e.key === "Enter" && !e.shiftKey) {
                e.preventDefault();
                handleSend();
              }
            }}
            placeholder={t("landmark.edit.aiPlaceholder")}
            className="min-h-[36px] max-h-[72px] resize-none text-sm"
            rows={1}
          />
          <Button
            size="icon"
            className="shrink-0 h-9 w-9"
            onClick={handleSend}
            disabled={!input.trim() || isLoading}
          >
            <Send className="w-4 h-4" />
          </Button>
        </div>
      </div>
    </>
  );
};

export default LandmarkAIEditPanel;
