import { useState, useRef, useEffect, lazy, Suspense, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible";
import { NearbyLandmarks } from "@/components/NearbyLandmarks";
import {
  ChevronLeft, Heart, Share2, MapPin, Star, Languages,
  Loader2, Clock, Globe, Navigation, ChevronDown,
  RotateCcw, BadgeCheck, HandMetal, Hotel, CalendarDays,
  Phone, Mail, Sparkles, Building2, FileText, Save, X, ImagePlus
} from "lucide-react";
import mapboxgl from "mapbox-gl";
import "mapbox-gl/dist/mapbox-gl.css";
import { BuildingStorySection } from "@/components/BuildingStorySection";
import { calculateDistance, getUserLocation, openNavigation } from "@/lib/geolocation";
import { NearbyRestaurantsSection } from "@/components/NearbyRestaurantsSection";
import { PullToRefresh } from "@/components/PullToRefresh";
import RestaurantRating from "@/components/RestaurantRating";
import { formatTrademarkSymbols } from "@/lib/textFormatting";
import { formatOpeningHours } from "@/lib/timeUtils";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import StoreAdBanner from "@/components/StoreAdBanner";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import ClaimRestaurantDialog from "@/components/ClaimRestaurantDialog";
import { useLoginRequired } from "@/hooks/useLoginRequired";

const RestaurantComments = lazy(() => import("@/components/RestaurantComments"));

interface HotelDetailPageProps {
  restaurant: any;
  localizedRestaurant: any;
  onBack: () => void;
  user: any;
  isFavorite: boolean;
  onToggleFavorite: () => void;
  onShare: () => void;
  onRefresh: () => Promise<void>;
  canInlineEdit?: boolean;
  isInlineEditMode?: boolean;
  setIsInlineEditMode?: (fn: (prev: boolean) => boolean) => void;
  draftRestaurant?: any;
  onDraftRestaurantChange?: (updates: any) => void;
  isSavingAll?: boolean;
  onSaveAll?: () => void;
  onCancelEdit?: () => void;
  onSelectBannerImage?: () => void;
  formDialog?: React.ReactNode;
}

export const HotelDetailPage = ({
  restaurant,
  localizedRestaurant,
  onBack,
  user,
  isFavorite,
  onToggleFavorite,
  onShare,
  onRefresh,
  canInlineEdit = false,
  isInlineEditMode = false,
  setIsInlineEditMode,
  draftRestaurant,
  onDraftRestaurantChange,
  isSavingAll = false,
  onSaveAll,
  onCancelEdit,
  onSelectBannerImage,
  formDialog,
}: HotelDetailPageProps) => {
  const { i18n, t } = useTranslation();
  const { getLocalizedField } = useLocalizedContent();
  const [showNavigationDialog, setShowNavigationDialog] = useState(false);
  const [hoursOpen, setHoursOpen] = useState(false);
  const [announcementOpen, setAnnouncementOpen] = useState(false);
  const [mapOpen, setMapOpen] = useState(true);
  const mapContainer = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<mapboxgl.Map | null>(null);
  const commentsSectionRef = useRef<HTMLDivElement>(null);
  const mapSectionRef = useRef<HTMLDivElement>(null);

  const [claimDialog, setClaimDialog] = useState<{ id: string; name: string; address?: string } | null>(null);
  const { requireLogin } = useLoginRequired();

  // Translation state
  const [translatedName, setTranslatedName] = useState<string | null>(null);
  const [translatedAddress, setTranslatedAddress] = useState<string | null>(null);
  const [translatedDescription, setTranslatedDescription] = useState<string | null>(null);
  const [isTranslating, setIsTranslating] = useState(false);
  const [showTranslation, setShowTranslation] = useState(false);
  
  // Story translation
  const [narrativeDisplay, setNarrativeDisplay] = useState<string | null>(null);
  const [showStoryTranslation, setShowStoryTranslation] = useState(false);
  const [isStoryTranslating, setIsStoryTranslating] = useState(false);

  // User distance
  const [userLocation, setUserLocation] = useState<{ lat: number; lng: number } | null>(null);
  useEffect(() => {
    getUserLocation().then(pos => {
      setUserLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude });
    }).catch(() => {});
  }, []);

  const distance = useMemo(() => {
    if (!userLocation || !restaurant.lat || !restaurant.lng) return null;
    return calculateDistance(userLocation.lat, userLocation.lng, restaurant.lat, restaurant.lng);
  }, [userLocation, restaurant.lat, restaurant.lng]);

  // Rating from comments
  const [ratingData, setRatingData] = useState<{ avg: number; count: number }>({ avg: 0, count: 0 });
  useEffect(() => {
    supabase
      .from('comments')
      .select('rating_value')
      .eq('target_id', restaurant.id)
      .eq('target_type', 'restaurant')
      .not('rating_value', 'is', null)
      .then(({ data }) => {
        if (data && data.length > 0) {
          const sum = data.reduce((acc, c) => acc + (c.rating_value || 0), 0);
          setRatingData({ avg: sum / data.length, count: data.length });
        }
      });
  }, [restaurant.id]);

  // Lazy load sections
  const [shouldLoadComments, setShouldLoadComments] = useState(false);
  const [shouldLoadMap, setShouldLoadMap] = useState(false);

  useEffect(() => {
    const observers: IntersectionObserver[] = [];
    if (commentsSectionRef.current) {
      const obs = new IntersectionObserver(([entry]) => {
        if (entry.isIntersecting) { setShouldLoadComments(true); obs.disconnect(); }
      }, { rootMargin: '200px' });
      obs.observe(commentsSectionRef.current);
      observers.push(obs);
    }
    if (mapSectionRef.current) {
      const obs = new IntersectionObserver(([entry]) => {
        if (entry.isIntersecting) { setShouldLoadMap(true); obs.disconnect(); }
      }, { rootMargin: '200px' });
      obs.observe(mapSectionRef.current);
      observers.push(obs);
    }
    return () => observers.forEach(o => o.disconnect());
  }, []);

  // Map initialization
  useEffect(() => {
    if (!shouldLoadMap || !mapContainer.current || !restaurant.lat || !restaurant.lng) return;
    if (mapInstance.current) return;
    const token = import.meta.env.VITE_MAPBOX_TOKEN;
    if (!token) return;
    mapboxgl.accessToken = token;
    const map = new mapboxgl.Map({
      container: mapContainer.current,
      style: 'mapbox://styles/mapbox/light-v11',
      center: [restaurant.lng, restaurant.lat],
      zoom: 15,
      interactive: true,
      cooperativeGestures: true,
    });
    new mapboxgl.Marker({ color: '#005C53' })
      .setLngLat([restaurant.lng, restaurant.lat])
      .addTo(map);
    mapInstance.current = map;
    return () => { map.remove(); mapInstance.current = null; };
  }, [shouldLoadMap, restaurant.lat, restaurant.lng]);

  // Translate story
  const translateStory = async (targetLang: string) => {
    const storyField = restaurant.photo_story_zh || restaurant.photo_story_en || '';
    if (!storyField) return;
    setIsStoryTranslating(true);
    try {
      const { data, error } = await supabase.functions.invoke('translate-content', {
        body: { text: storyField, targetLang }
      });
      if (!error && data?.translatedText) {
        setNarrativeDisplay(data.translatedText);
        setShowStoryTranslation(true);
      }
    } catch {} finally {
      setIsStoryTranslating(false);
    }
  };

  // Handle translate toggle
  const handleTranslate = async () => {
    const targetLang = i18n.language;
    if (showTranslation) {
      setTranslatedName(null);
      setTranslatedAddress(null);
      setTranslatedDescription(null);
      setNarrativeDisplay(null);
      setShowTranslation(false);
      setShowStoryTranslation(false);
      return;
    }
    setIsTranslating(true);
    try {
      const parts = [localizedRestaurant.name];
      if (restaurant.address) parts.push(restaurant.address);
      const desc = localizedRestaurant.description?.replace(/<[^>]*>/g, '').trim();
      if (desc) parts.push(localizedRestaurant.description);
      const combined = parts.join('\n---SECTION---\n');
      try {
        const { data, error } = await supabase.functions.invoke('translate-content', {
          body: { text: combined, targetLang }
        });
        if (!error && data?.translatedText) {
          const splitParts = data.translatedText.split(/---SECTION---/);
          setTranslatedName(splitParts[0]?.trim() || null);
          setTranslatedAddress(splitParts[1]?.trim() || null);
          setTranslatedDescription(splitParts[2]?.trim() || null);
        }
      } catch {}
      if (!showStoryTranslation) await translateStory(targetLang);
      setShowTranslation(true);
    } finally {
      setIsTranslating(false);
    }
  };

  const isMobile = typeof window !== 'undefined' && window.innerWidth < 768;
  const yearEstablished = restaurant.year_established;

  return (
    <>
    <PullToRefresh onRefresh={onRefresh}>
      <div className="min-h-screen bg-secondary/20">
        {/* Hero Image - Taller for hotels */}
        <div className="relative h-[45vh] md:h-[50vh] overflow-hidden bg-muted">
          <img
            src={(isInlineEditMode && draftRestaurant?.banner_url) || restaurant.cover_image_url || restaurant.image_url || "https://images.unsplash.com/photo-1566073771259-6a8506099945?w=1200&q=80"}
            alt={localizedRestaurant.name}
            className="w-full h-full object-cover"
            loading="eager"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-background/95 via-background/30 to-transparent" />
          
          {/* Banner image edit button */}
          {isInlineEditMode && canInlineEdit && onSelectBannerImage && (
            <div className="absolute top-16 left-4 z-20">
              <Button type="button" size="sm" variant="secondary" className="shadow-lg" onClick={onSelectBannerImage}>
                <ImagePlus className="w-4 h-4 mr-1" />
                {t("admin.changeBanner", "更换封面")}
              </Button>
            </div>
          )}
          
          {/* Hotel Badge overlay */}
          <div className="absolute bottom-24 left-6 md:left-8 z-10">
            <Badge className="bg-amber-600/90 text-white border-0 gap-1.5 px-3 py-1.5 text-sm font-medium backdrop-blur-sm">
              <Hotel className="w-4 h-4" />
              {t("hotel.historicHotel", "历史名人酒店")}
            </Badge>
            {yearEstablished && (
              <Badge variant="secondary" className="ml-2 gap-1 px-2.5 py-1.5 text-sm backdrop-blur-sm bg-background/60">
                <CalendarDays className="w-3.5 h-3.5" />
                {t("hotel.since", "始于")} {yearEstablished}
              </Badge>
            )}
          </div>
          
          {/* Back Button */}
          <Button
            asChild
            variant="secondary"
            size="icon"
            className="absolute top-4 left-4 z-20"
          >
            <button onClick={onBack}>
              <ChevronLeft className="w-5 h-5" />
            </button>
          </Button>

          {/* Top-right action buttons */}
          <div className="absolute top-4 right-4 flex items-center gap-2 z-20">
            {canInlineEdit && formDialog}
            {canInlineEdit && setIsInlineEditMode && (
              <Button
                variant="secondary"
                className={`shadow-lg backdrop-blur-sm ${isInlineEditMode ? 'bg-primary text-primary-foreground hover:bg-primary/90' : 'bg-background/60'}`}
                onClick={() => setIsInlineEditMode((prev) => !prev)}
                aria-label={t("restaurant.freeEdit", "Free Edit")}
              >
                <FileText className="w-4 h-4 mr-1" />
                {t("restaurant.freeEdit", "Free Edit")}
              </Button>
            )}
            <Button variant="secondary" size="icon" className="shadow-lg" onClick={onShare}>
              <Share2 className="w-5 h-5" />
            </Button>
            {user && (
              <Button variant="secondary" size="icon" onClick={onToggleFavorite}>
                <Heart className={`w-5 h-5 ${isFavorite ? 'fill-destructive text-destructive' : ''}`} />
              </Button>
            )}
          </div>
        </div>

        <div className="container mx-auto max-w-6xl px-4 -mt-20 relative z-10 pb-12">
          <Card className="shadow-large">
            <CardHeader className="relative">
              {restaurant.lat && restaurant.lng && (
                <div className="absolute top-4 right-4 md:top-6 md:right-6 z-10">
                  <NearbyLandmarks
                    lat={restaurant.lat}
                    lng={restaurant.lng}
                    restaurantId={restaurant.id}
                  />
                </div>
              )}
              <div className="flex flex-col md:flex-row md:items-start md:justify-between gap-4">
                <div>
                  <div className="mb-2 flex flex-wrap gap-2">
                    {localizedRestaurant.type.slice(0, 3).map((type: string, idx: number) => (
                      <Badge key={idx} variant="secondary">{type}</Badge>
                    ))}
                  </div>
                  <CardTitle className="text-3xl mb-1 flex items-center gap-2 flex-wrap">
                    {translatedName || formatTrademarkSymbols(localizedRestaurant.name)}
                    {(['basic', 'complete', 'full'].includes(restaurant.store_level || '')) && (
                      <BadgeCheck className="w-6 h-6 text-primary shrink-0" />
                    )}
                    {!['basic', 'complete', 'full'].includes(restaurant.store_level || '') && (
                      <button
                        className="inline-flex items-center gap-1 bg-amber-500/90 backdrop-blur-sm rounded-full px-2.5 py-1 shadow-sm hover:bg-amber-600 transition-colors"
                        onClick={() => {
                          if (!requireLogin()) return;
                          setClaimDialog({
                            id: restaurant.id,
                            name: restaurant.name,
                            address: restaurant.address,
                          });
                        }}
                        title={t("restaurants.unclaimedStore", "未认领")}
                      >
                        <HandMetal className="w-4 h-4 text-white" />
                        <span className="text-xs font-medium text-white">{t("restaurants.unclaimedStore", "未认领")}</span>
                      </button>
                    )}
                  </CardTitle>
                  {/* Original name if different */}
                  {(() => {
                    const displayed = translatedName || localizedRestaurant.name;
                    const original = restaurant?.name || "";
                    const isDual = original && displayed && original.trim().toLowerCase() !== String(displayed).trim().toLowerCase();
                    return isDual ? (
                      <p className="text-sm text-muted-foreground mb-2">{formatTrademarkSymbols(original)}</p>
                    ) : null;
                  })()}
                  
                  <div className="flex items-center gap-3 mb-2 flex-wrap">
                    {distance !== null && (
                      <div className="flex items-center gap-1">
                        <Navigation className="w-4 h-4 text-primary" />
                        <span className="font-semibold text-base">{distance.toFixed(1)} km</span>
                      </div>
                    )}
                    <div className="flex items-center gap-1">
                      <Star className={`w-5 h-5 ${ratingData.count > 0 ? "fill-accent text-accent" : "text-muted-foreground"}`} />
                      {ratingData.count > 0 ? (
                        <span className="font-semibold text-base">
                          {ratingData.avg.toFixed(1)}
                          <span className="text-muted-foreground font-normal text-sm ml-1">({ratingData.count})</span>
                        </span>
                      ) : (
                        <span className="text-sm text-muted-foreground">
                          {t("restaurant.noRatingWithHint")}
                        </span>
                      )}
                    </div>
                    
                    {/* Translate button */}
                    <button
                      className={`inline-flex items-center gap-1 min-h-[32px] py-1 px-2 rounded-md text-xs font-medium transition-all duration-200 active:scale-95 ${
                        (isTranslating || isStoryTranslating)
                          ? "text-muted-foreground cursor-wait" 
                          : showTranslation 
                            ? "text-primary bg-primary/10" 
                            : "text-muted-foreground hover:text-primary"
                      }`}
                      disabled={isTranslating || isStoryTranslating}
                      onClick={handleTranslate}
                    >
                      {(isTranslating || isStoryTranslating) ? (
                        <Loader2 className="h-3.5 w-3.5 animate-spin" />
                      ) : showTranslation ? (
                        <RotateCcw className="h-3.5 w-3.5" />
                      ) : (
                        <Languages className="h-3.5 w-3.5" />
                      )}
                      <span>
                        {(isTranslating || isStoryTranslating)
                          ? t("translate.translating", "翻译中...") 
                          : showTranslation 
                            ? t("translate.showOriginal", "显示原文") 
                            : t("translate.button", "翻译")}
                      </span>
                    </button>
                  </div>
                  
                  {/* Description */}
                  {isInlineEditMode && canInlineEdit && onDraftRestaurantChange ? (
                    <div className="mt-3 space-y-2">
                      <Label className="text-xs text-muted-foreground">{t("admin.description", "描述")}</Label>
                      <Textarea
                        value={draftRestaurant?.description || ""}
                        onChange={(e) => onDraftRestaurantChange({ description: e.target.value })}
                        placeholder={t("admin.descriptionPlaceholder", "输入酒店描述...")}
                        className="min-h-[80px] text-sm"
                      />
                    </div>
                  ) : localizedRestaurant.description && localizedRestaurant.description.replace(/<[^>]*>/g, '').trim() !== '' ? (
                    <div 
                      className="text-muted-foreground prose prose-sm dark:prose-invert max-w-none [&_*]:!text-inherit [&_a]:!text-primary [&_a]:underline mt-3"
                      dangerouslySetInnerHTML={{ __html: translatedDescription || localizedRestaurant.description }}
                    />
                  ) : null}
                </div>
              </div>
            </CardHeader>

            <CardContent className="space-y-6">
              {/* Building Story - History & Celebrity connections */}
              <BuildingStorySection
                restaurant={restaurant}
                variant="card"
                narrativeOverride={narrativeDisplay}
                onTranslateClick={handleTranslate}
                isTranslating={isStoryTranslating || isTranslating}
                showTranslation={showTranslation}
              />

              {/* Separator with hotel icon */}
              <div className="relative my-3">
                <Separator />
                <div className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 bg-background px-3">
                  <Hotel className="h-4 w-4 text-muted-foreground" />
                </div>
              </div>

              {/* Hotel Info Section */}
              {(() => {
                const infoItems: { icon: React.ReactNode; label: string; value: string | number }[] = [];
                
                if (yearEstablished) {
                  infoItems.push({ icon: <CalendarDays className="w-5 h-5 text-primary mb-2" />, label: t("hotel.established", "建立年份"), value: yearEstablished });
                }
                if (restaurant.tripadvisor_rating) {
                  infoItems.push({ icon: <Star className="w-5 h-5 text-green-600 mb-2" />, label: "TripAdvisor", value: restaurant.tripadvisor_rating });
                }
                if (restaurant.dress_code) {
                  infoItems.push({ icon: <Sparkles className="w-5 h-5 text-primary mb-2" />, label: t("hotel.dressCode", "着装要求"), value: restaurant.dress_code });
                }
                if (restaurant.chef_name) {
                  infoItems.push({ icon: <Building2 className="w-5 h-5 text-primary mb-2" />, label: t("hotel.manager", "管理"), value: restaurant.chef_name });
                }
                if (restaurant.price_range) {
                  infoItems.push({ icon: <span className="text-lg text-primary mb-2">💰</span>, label: t("hotel.priceRange", "价格区间"), value: restaurant.price_range });
                }
                if (restaurant.city && restaurant.country) {
                  infoItems.push({ icon: <MapPin className="w-5 h-5 text-primary mb-2" />, label: t("hotel.location", "所在地"), value: `${restaurant.city}, ${restaurant.country}` });
                }
                if (restaurant.rating && restaurant.rating > 0) {
                  infoItems.push({ icon: <Star className="w-5 h-5 text-amber-500 mb-2" />, label: t("hotel.userRating", "用户评分"), value: `${restaurant.rating} ★` });
                }
                
                // Determine grid columns based on item count
                const gridCols = infoItems.length === 1 ? 'grid-cols-1' : infoItems.length === 2 ? 'grid-cols-2' : infoItems.length === 3 ? 'grid-cols-3' : 'grid-cols-2 md:grid-cols-4';
                
                return infoItems.length > 0 ? (
                  <div className={`grid ${gridCols} gap-3`}>
                    {infoItems.map((item, idx) => (
                      <div key={idx} className="flex flex-col items-center p-4 rounded-xl bg-muted/50 text-center">
                        {item.icon}
                        <span className="text-xs text-muted-foreground">{item.label}</span>
                        <span className="font-semibold text-sm">{item.value}</span>
                      </div>
                    ))}
                  </div>
                ) : null;
              })()}

              {/* Official Website Button - Main CTA for hotels */}
              {restaurant.show_website_button !== false && (restaurant.official_website || restaurant.website_url) && (
                <Button 
                  className="w-full h-12 rounded-xl bg-amber-600 hover:bg-amber-700 text-white"
                  onClick={() => {
                    window.open(restaurant.official_website || restaurant.website_url, '_blank', 'noopener,noreferrer');
                  }}
                >
                  <Globe className="w-4 h-4 mr-2" />
                  {t("hotel.visitWebsite", "访问酒店官网")}
                </Button>
              )}

              {/* Contact Info */}
              {isInlineEditMode && canInlineEdit && onDraftRestaurantChange ? (
                <div className="space-y-4 p-4 rounded-lg border-2 border-dashed border-primary/30 bg-primary/5">
                  <p className="text-xs font-medium text-primary">{t("restaurant.freeEdit", "自由编辑")} — {t("admin.contactInfo", "联系信息")}</p>
                  <div className="grid md:grid-cols-2 gap-3">
                    <div className="space-y-1.5">
                      <Label className="text-xs">{t("restaurant.address")}</Label>
                      <Input
                        value={draftRestaurant?.address || ""}
                        onChange={(e) => onDraftRestaurantChange({ address: e.target.value })}
                        placeholder={t("restaurant.addressPlaceholder", "输入地址")}
                        className="h-9 text-sm"
                      />
                    </div>
                    <div className="space-y-1.5">
                      <Label className="text-xs">{t("restaurant.phone")}</Label>
                      <Input
                        value={draftRestaurant?.phone || ""}
                        onChange={(e) => onDraftRestaurantChange({ phone: e.target.value })}
                        placeholder={t("restaurant.phonePlaceholder", "输入电话")}
                        className="h-9 text-sm"
                      />
                    </div>
                    <div className="space-y-1.5">
                      <Label className="text-xs">{t("restaurant.email", "Email")}</Label>
                      <Input
                        value={draftRestaurant?.email || ""}
                        onChange={(e) => onDraftRestaurantChange({ email: e.target.value })}
                        placeholder="email@example.com"
                        className="h-9 text-sm"
                      />
                    </div>
                  </div>
                  {/* Announcement edit */}
                  <div className="space-y-1.5">
                    <Label className="text-xs">{t("restaurant.announcement", "公告")}</Label>
                    <Textarea
                      value={draftRestaurant?.announcement || ""}
                      onChange={(e) => onDraftRestaurantChange({ announcement: e.target.value })}
                      placeholder={t("admin.announcementPlaceholder", "输入公告内容...")}
                      className="min-h-[60px] text-sm"
                    />
                  </div>
                </div>
              ) : (
              <div className={`grid ${restaurant.opening_hours ? 'md:grid-cols-2' : 'grid-cols-1'} gap-4`}>
                <div className="flex flex-col gap-3 p-4 rounded-lg bg-muted/50">
                  {/* Address */}
                  <div className="flex items-start gap-3">
                    <MapPin className="w-5 h-5 text-primary mt-0.5 flex-shrink-0" />
                    <div className="flex-1">
                      <p className="font-medium text-card-foreground">{t("restaurant.address")}</p>
                      <p className="text-muted-foreground">{translatedAddress || restaurant.address}</p>
                    </div>
                  </div>
                  {/* Navigation Button (Mobile only) */}
                  {isMobile && (
                    <Button 
                      variant="secondary"
                      size="sm"
                      className="w-full rounded-lg"
                      onClick={() => setShowNavigationDialog(true)}
                    >
                      <Navigation className="w-4 h-4 mr-2" />
                      {t("restaurant.getDirections")}
                    </Button>
                  )}
                  {/* Phone */}
                  {restaurant.phone && (
                    <div className="flex items-start gap-3">
                      <Phone className="w-5 h-5 text-primary mt-0.5 flex-shrink-0" />
                      <div className="flex-1">
                        <p className="font-medium text-card-foreground">{t("restaurant.phone")}</p>
                        <a href={`tel:${restaurant.phone}`} className="text-primary underline">{restaurant.phone}</a>
                      </div>
                    </div>
                  )}
                  {/* Email */}
                  {restaurant.email && (
                    <div className="flex items-start gap-3">
                      <Mail className="w-5 h-5 text-primary mt-0.5 flex-shrink-0" />
                      <div className="flex-1">
                        <p className="font-medium text-card-foreground">{t("restaurant.email", "Email")}</p>
                        <a href={`mailto:${restaurant.email}`} className="text-primary underline">{restaurant.email}</a>
                      </div>
                    </div>
                  )}
                </div>

                {/* Opening Hours */}
                {restaurant.opening_hours && (
                  <Collapsible
                    open={hoursOpen}
                    onOpenChange={setHoursOpen}
                    className="flex items-start gap-3 p-4 rounded-lg bg-muted/50"
                  >
                    <Clock className="w-5 h-5 text-primary mt-0.5 flex-shrink-0" />
                    <div className="flex-1">
                      <CollapsibleTrigger className="w-full">
                        <div className="flex items-center justify-between">
                          <div className="flex flex-col items-start">
                            <p className="font-medium text-card-foreground">{t("restaurant.hours")}</p>
                            {!hoursOpen && (
                              <p className="text-sm text-muted-foreground mt-0.5">
                                {t("restaurant.today")} {formatOpeningHours(restaurant.opening_hours)}
                              </p>
                            )}
                          </div>
                          <ChevronDown className={`w-5 h-5 text-muted-foreground transition-transform ${hoursOpen ? 'rotate-180' : ''}`} />
                        </div>
                      </CollapsibleTrigger>
                      <CollapsibleContent className="mt-3">
                        <div className="space-y-2">
                          {(() => {
                            const days = ['monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday', 'sunday'];
                            const dayKeys: Record<string, string> = {
                              monday: 'dayMon', tuesday: 'dayTue', wednesday: 'dayWed',
                              thursday: 'dayThu', friday: 'dayFri', saturday: 'daySat', sunday: 'daySun'
                            };
                            const currentDay = days[new Date().getDay() === 0 ? 6 : new Date().getDay() - 1];
                            return days.map((day) => {
                              const hours = restaurant.opening_hours[day];
                              const isToday = day === currentDay;
                              let hoursText = 'N/A';
                              if (hours) {
                                if (hours.closed) hoursText = t("restaurant.closed");
                                else if (hours.splitShift) hoursText = `${hours.open} - ${hours.close}, ${hours.open2} - ${hours.close2}`;
                                else hoursText = `${hours.open} - ${hours.close}`;
                              }
                              return (
                                <div key={day} className={`flex justify-between items-center py-1.5 px-2 rounded ${isToday ? 'bg-primary/10 border border-primary/20' : ''}`}>
                                  <span className={`text-sm font-medium ${isToday ? 'text-primary' : 'text-foreground'}`}>
                                    {t(`restaurant.${dayKeys[day]}`)}
                                    {isToday && <span className="ml-2 text-xs">({t("restaurant.today")})</span>}
                                  </span>
                                  <span className={`text-sm ${isToday ? 'text-primary font-semibold' : 'text-muted-foreground'} ${hours?.closed ? 'italic' : ''}`}>
                                    {hoursText}
                                  </span>
                                </div>
                              );
                            });
                          })()}
                        </div>
                      </CollapsibleContent>
                    </div>
                  </Collapsible>
                )}

                {/* Announcement */}
                {(getLocalizedField(restaurant, "announcement") || restaurant.announcement_zh) && (
                  <Collapsible
                    open={announcementOpen}
                    onOpenChange={setAnnouncementOpen}
                    className="flex items-start gap-3 p-4 rounded-lg bg-muted/50"
                  >
                    <Sparkles className="w-5 h-5 text-primary mt-0.5 flex-shrink-0" />
                    <div className="flex-1">
                      <CollapsibleTrigger className="w-full">
                        <div className="flex items-center justify-between">
                          <p className="font-medium text-card-foreground">{t("restaurant.announcement")}</p>
                          <ChevronDown className={`w-5 h-5 text-muted-foreground transition-transform ${announcementOpen ? 'rotate-180' : ''}`} />
                        </div>
                      </CollapsibleTrigger>
                      <CollapsibleContent className="mt-3">
                        <div className="p-3 rounded-md bg-primary/5 border border-primary/10">
                          <p className="text-sm text-foreground whitespace-pre-wrap">
                            {getLocalizedField(restaurant, "announcement") || restaurant.announcement_zh}
                          </p>
                        </div>
                      </CollapsibleContent>
                    </div>
                  </Collapsible>
                )}
              </div>
              )}

              {/* Navigation Button - Desktop */}
              {!isMobile && (
                <Button 
                  variant="secondary"
                  className="w-full h-12 rounded-xl"
                  onClick={() => setShowNavigationDialog(true)}
                >
                  <Navigation className="w-4 h-4 mr-2" />
                  {t("restaurant.getDirections")}
                </Button>
              )}

              {/* Navigation Dialog */}
              <AlertDialog open={showNavigationDialog} onOpenChange={setShowNavigationDialog}>
                <AlertDialogContent className="max-w-[320px] w-[calc(100%-2rem)] mx-auto border-0 bg-background/80 backdrop-blur-2xl shadow-2xl rounded-[28px] overflow-hidden p-6">
                  <div className="absolute inset-0 rounded-[28px] bg-gradient-to-b from-background/40 via-transparent to-transparent pointer-events-none" />
                  <AlertDialogHeader className="relative text-center space-y-3">
                    <div className="mx-auto w-14 h-14 rounded-2xl bg-gradient-to-br from-primary/10 to-primary/5 flex items-center justify-center shadow-sm shrink-0">
                      <Navigation className="w-7 h-7 text-primary shrink-0" strokeWidth={1.5} />
                    </div>
                    <div className="space-y-1.5 px-1">
                      <AlertDialogTitle className="text-base font-semibold tracking-tight text-foreground">
                        {t("navigation.confirmTitle")}
                      </AlertDialogTitle>
                      <AlertDialogDescription className="text-sm text-muted-foreground/80 leading-relaxed break-words">
                        {t("navigation.confirmDescriptionSimple", { destination: localizedRestaurant.name })}
                      </AlertDialogDescription>
                    </div>
                  </AlertDialogHeader>
                  <AlertDialogFooter className="relative flex-col gap-2 pt-4 mt-1">
                    <AlertDialogAction
                      onClick={() => {
                        openNavigation(restaurant.lat, restaurant.lng, localizedRestaurant.name);
                        setShowNavigationDialog(false);
                      }}
                      className="w-full rounded-xl h-11 bg-primary hover:bg-primary/90 text-primary-foreground font-medium shadow-lg shadow-primary/25"
                    >
                      {t("navigation.openNavigation", "获取路线")}
                    </AlertDialogAction>
                    <AlertDialogCancel className="w-full rounded-xl h-11 bg-secondary hover:bg-secondary/80 border-0 text-muted-foreground font-medium mt-0">
                      {t("common.cancel")}
                    </AlertDialogCancel>
                  </AlertDialogFooter>
                </AlertDialogContent>
              </AlertDialog>

              {/* Nearby restaurants/landmarks */}
              {restaurant.lat && restaurant.lng && (
                <NearbyRestaurantsSection
                  lat={restaurant.lat}
                  lng={restaurant.lng}
                  currentRestaurantId={restaurant.id}
                />
              )}

              {/* Store Ad Banner */}
              <StoreAdBanner country={restaurant.country || null} city={restaurant.city || null} storeLevel={restaurant.store_level || 'shell'} />

              {/* Map */}
              <div ref={mapSectionRef}>
                <Collapsible open={mapOpen} onOpenChange={setMapOpen} className="p-4 rounded-lg bg-muted/50">
                  <CollapsibleTrigger className="w-full">
                    <div className="flex items-center justify-between mb-4">
                      <h2 className="text-2xl font-bold">{t("restaurant.map")}</h2>
                      <ChevronDown className={`w-5 h-5 text-muted-foreground transition-transform ${mapOpen ? 'rotate-180' : ''}`} />
                    </div>
                  </CollapsibleTrigger>
                  <CollapsibleContent>
                    {shouldLoadMap ? (
                      <div ref={mapContainer} className="h-[350px] rounded-lg overflow-hidden bg-muted" />
                    ) : (
                      <div className="h-[350px] rounded-lg bg-muted flex items-center justify-center">
                        <Loader2 className="w-6 h-6 animate-spin text-muted-foreground" />
                      </div>
                    )}
                  </CollapsibleContent>
                </Collapsible>
              </div>

              <Separator />

              {/* Rating */}
              <RestaurantRating restaurantId={restaurant.id} />

              <Separator />

              {/* Comments */}
              <div ref={commentsSectionRef}>
                {shouldLoadComments ? (
                  <Suspense fallback={
                    <div className="flex items-center justify-center py-12">
                      <Loader2 className="w-8 h-8 animate-spin text-primary" />
                    </div>
                  }>
                    <RestaurantComments restaurantId={restaurant.id} />
                  </Suspense>
                ) : (
                  <div className="flex items-center justify-center py-12">
                    <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
                  </div>
                )}
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Floating Save/Cancel Bar */}
        {isInlineEditMode && canInlineEdit && (
          <div className="fixed bottom-0 left-0 right-0 z-50 bg-background/95 backdrop-blur-xl border-t border-border shadow-2xl">
            <div className="container mx-auto max-w-6xl px-4 py-3 flex items-center justify-between gap-3">
              <p className="text-sm text-muted-foreground hidden sm:block">
                <FileText className="w-4 h-4 inline mr-1" />
                {t("restaurant.freeEdit", "自由编辑")}
              </p>
              <div className="flex items-center gap-2 ml-auto">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={onCancelEdit}
                  disabled={isSavingAll}
                >
                  <X className="w-4 h-4 mr-1" />
                  {t("common.cancel", "取消")}
                </Button>
                <Button
                  size="sm"
                  onClick={onSaveAll}
                  disabled={isSavingAll}
                  className="min-w-[80px]"
                >
                  {isSavingAll ? (
                    <Loader2 className="w-4 h-4 animate-spin" />
                  ) : (
                    <>
                      <Save className="w-4 h-4 mr-1" />
                      {t("common.save", "保存")}
                    </>
                  )}
                </Button>
              </div>
            </div>
          </div>
        )}
      </div>
    </PullToRefresh>

    <ClaimRestaurantDialog
      open={!!claimDialog}
      onOpenChange={(open) => !open && setClaimDialog(null)}
      restaurant={claimDialog}
    />
    </>
  );
};
