import { useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { useTranslation } from "react-i18next";

export interface LandmarkEditField {
  fieldName: string;
  oldValue: string;
  newValue: string;
}

export function useLandmarkEdit(landmarkId: string) {
  const { user } = useAuth();
  const { t } = useTranslation();
  const [isSubmitting, setIsSubmitting] = useState(false);

  const submitEdits = async (edits: LandmarkEditField[], editLang: string) => {
    if (!user) {
      toast.error(t("landmark.edit.loginRequired"));
      return false;
    }

    if (edits.length === 0) {
      toast.info(t("landmark.edit.noChanges"));
      return false;
    }

    // Filter out unchanged fields
    const changedEdits = edits.filter(e => e.oldValue !== e.newValue && e.newValue.trim() !== "");
    if (changedEdits.length === 0) {
      toast.info(t("landmark.edit.noChanges"));
      return false;
    }

    setIsSubmitting(true);
    try {
      // Insert all edit records
      const records = changedEdits.map(e => ({
        landmark_id: landmarkId,
        user_id: user.id,
        edit_lang: editLang,
        field_name: e.fieldName,
        old_value: e.oldValue || null,
        new_value: e.newValue,
        status: "pending" as const,
      }));

      const { data: insertedEdits, error: insertError } = await supabase
        .from("landmark_edits")
        .insert(records)
        .select("id");

      if (insertError) throw insertError;

      // Trigger AI moderation for each edit
      const moderationPromises = (insertedEdits || []).map(edit =>
        supabase.functions.invoke("moderate-landmark-edit", {
          body: { editId: edit.id },
        })
      );

      const results = await Promise.allSettled(moderationPromises);
      
      const allApproved = results.every(r => {
        if (r.status === "fulfilled" && r.value.data) {
          return r.value.data.status === "approved";
        }
        return false;
      });

      if (allApproved) {
        toast.success(t("landmark.edit.approved"));
      } else {
        toast.success(t("landmark.edit.submitted"));
      }

      return true;
    } catch (error) {
      console.error("Failed to submit landmark edits:", error);
      toast.error(t("landmark.edit.submitFailed"));
      return false;
    } finally {
      setIsSubmitting(false);
    }
  };

  return { submitEdits, isSubmitting };
}
